private fun getNewlineWithIndent(modifierListRoot: ASTNode): String {    // Special handling for annotations inside TYPE_ARGUMENT_LIST    if (modifierListRoot.isPartOf(TYPE_ARGUMENT_LIST)) {
        // Find the TYPE_ARGUMENT_LIST node
        var parent = modifierListRoot.treeParent        while (parent != null && parent.elementType != TYPE_ARGUMENT_LIST) {            parent = parent.treeParent        }        if (parent != null) {
            // Find the whitespace before the TYPE_ARGUMENT_LIST's parent            val nodeBeforeTAL = parent.treeParent?.treePrev as? PsiWhiteSpace
            val baseIndent = if (nodeBeforeTAL?.text?.contains('\n') == true) {                nodeBeforeTAL.text.substring(nodeBeforeTAL.text.lastIndexOf('\n'))            } else {
                // Try to find the indentation of the current line                parent.leaves(forward = false)                    .firstOrNull { it.isWhiteSpaceWithNewline() }                    ?.text                    ?.substring(it.text.lastIndexOf('\n'))                    ?: "\n"            }
            // Add one level of indentation (4 spaces by default)            return baseIndent + "    "
        }
        return "\n"
    }
